var config = require('../../config');
var request = require('supertest');
var pack = require('../../controllers/pack')
var e = require('expect.js');
var connect = require('connect');
var http = require('http');

var port = Math.floor(Math.random()* 9000 + 1000);

var app = connect();
var p = pack(config);
app.use('/pack', p.middleware());
app = http.createServer(app);


describe('controllers pack', function (done) {
  before(function (done) {
    app.listen(port, done);
  });

  after(function (done) {
    app.close(done);
  });

  it('pack program fail no appname', function (done) {
    request(app)
    .get('/pack')
    .expect('appname is Invalid')
    .expect(200)
    .end(function (err, res, body) {
    	e(err).to.eql(null);
    	done();
    });
  });

  it('pack program success', function (done) {
    request(app)
    .get('/pack?appname=sqlscan')
    .expect(200)
    .expect('pack sqlscan ok')
    .end(function (err, res, body) {
    	e(err).to.eql(null);
    	done();
    });
  });

  it('pack program error happen', function (done) {
    var _initRep = p.project.initRep;
    p.project.initRep = function (appname, cb) {
      process.nextTick(function () {
      	cb('mock error');
      });
    }
    request(app)
    .get('/pack?appname=sqlscan')
    .expect(500)
    .end(function (err, res, body) {
    	e(err).to.eql(null);
    	p.project.initRep = _initRep;
    	done();
    });
  });
});